// --- Helper Functions ---

// Standard Base64 Encode
function btoa(input) {
    var chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=';
    var str = String(input);
    var output = '';

    for (var block, charCode, idx = 0, map = chars;
         str.charAt(idx | 0) || (map = '=', idx % 1);
         output += map.charAt(63 & block >> 8 - idx % 1 * 8)) {

        charCode = str.charCodeAt(idx += 3 / 4);
        if (charCode > 0xFF) {
            throw new Error("'btoa' failed: The string to be encoded contains characters outside of the Latin1 range.");
        }
        block = block << 8 | charCode;
    }
    return output;
}

// RFC 2047 Encoder (for Headers like Subject)
function encodeHeader(text) {
    if (!text) return "";
    // Only encode if contains non-ASCII
    if (/[^\x00-\x7F]/.test(text)) {
        var encoded = btoa(unescape(encodeURIComponent(text)));
        return '=?UTF-8?B?' + encoded + '?=';
    }
    return text;
}

// --- Main Logic ---

var nl = "\r\n";
var boundary = "===============" + Date.now() + "==";
var headers = [];

// 1. Mandatory Date
headers.push("Date: " + new Date().toUTCString());

// 2. Mandatory From (Use input or default)
if (input.from) {
    headers.push("From: " + input.from);
}

// 3. To/Cc/Bcc
if (input.to && input.to.length > 0) headers.push("To: " + input.to.join(", "));
if (input.cc && input.cc.length > 0) headers.push("Cc: " + input.cc.join(", "));
if (input.bcc && input.bcc.length > 0) headers.push("Bcc: " + input.bcc.join(", "));

// 4. Subject (Encoded)
headers.push("Subject: " + encodeHeader(input.subject || ""));

// 5. Threading (In-Reply-To / References)
if (input.inReplyTo) {
    var replyId = input.inReplyTo;
    // Ensure it is wrapped in <...>
    if (replyId.charAt(0) !== '<') {
        replyId = '<' + replyId + '@mail.gmail.com>';
    }
    headers.push("In-Reply-To: " + replyId);
    headers.push("References: " + replyId);
}

headers.push("MIME-Version: 1.0");

// --- Construct Body ---
var bodyContent = "";

if (input.htmlBody && input.body) {
    // Multipart/Alternative
    headers.push('Content-Type: multipart/alternative; boundary="' + boundary + '"');

    bodyContent += "--" + boundary + nl;
    bodyContent += 'Content-Type: text/plain; charset="UTF-8"' + nl;
    bodyContent += 'Content-Transfer-Encoding: 7bit' + nl + nl;
    bodyContent += input.body + nl + nl;

    bodyContent += "--" + boundary + nl;
    bodyContent += 'Content-Type: text/html; charset="UTF-8"' + nl;
    bodyContent += 'Content-Transfer-Encoding: 7bit' + nl + nl;
    bodyContent += input.htmlBody + nl + nl;

    bodyContent += "--" + boundary + "--";

} else if (input.htmlBody) {
    // HTML Only
    headers.push('Content-Type: text/html; charset="UTF-8"');
    headers.push('Content-Transfer-Encoding: 7bit');
    bodyContent = input.htmlBody;

} else {
    // Plain Text Only
    headers.push('Content-Type: text/plain; charset="UTF-8"');
    headers.push('Content-Transfer-Encoding: 7bit');
    bodyContent = input.body || "";
}

var fullMessage = headers.join(nl) + nl + nl + bodyContent;

// --- Encode to Base64URL ---
// 1. Encode to Base64 (handling UTF-8)
var encoded = btoa(unescape(encodeURIComponent(fullMessage)));

// 2. Make URL-Safe (Replace +/, remove =)
var raw = encoded.replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');

// --- Output ---
var result = {
    "raw": raw
};

if (input.threadId) {
    result.threadId = input.threadId;
}

